    notifyCustomer: false,
    notifyOwner: true,
    notifyDev: true
  },

  'internal.api.get_professional': {
    severity: 'critical',
    notifyCustomer: false,
    notifyOwner: true,
    notifyDev: true
  },

  'internal.api.get_context': {
    severity: 'critical',
    notifyCustomer: false,
    notifyOwner: true,
    notifyDev: true
  },

  'internal.api.get_appointment': {
    severity: 'critical',
    notifyCustomer: false,
    notifyOwner: true,
    notifyDev: true,
    customerMessage: 'Não consegui verificar seus agendamentos. Vou pedir para a equipe verificar e te retornar. Gostaria de mais alguma coisa?'
  },

  'internal.api.complete_appointments': {
    severity: 'low',
    notifyCustomer: false,
    notifyOwner: true,
    notifyDev: true
  },

  'internal.redis.keys': {
    severity: 'medium',
    notifyCustomer: false,
    notifyOwner: false,
    notifyDev: true
  },

  'internal.redis.buffer': {
    severity: 'high',
    notifyCustomer: true,
    notifyOwner: false,
    notifyDev: true,
    customerMessage: 'Tive uma instabilidade para recuperar a etapa anterior. Poderia me confirmar novamente o que deseja fazer?'
  },

  'internal.redis.context': {
    severity: 'medium',
    notifyCustomer: false,
    notifyOwner: false,
    notifyDev: true
  },

  'internal.redis.set_pending': {
    severity: 'high',
    notifyCustomer: true,
    notifyOwner: false,
    notifyDev: true,
    customerMessage: 'Tive uma instabilidade para recuperar a etapa anterior. Poderia me confirmar novamente o que deseja fazer?'
  },

  'internal.redis.get_pending': {
    severity: 'high',
    notifyCustomer: true,
    notifyOwner: false,
    notifyDev: true,
    customerMessage: 'Tive uma instabilidade para recuperar a etapa anterior. Poderia me confirmar novamente o que deseja fazer?'
  },

  'internal.redis.get_timeout': {
    severity: 'high',
    notifyCustomer: true,
    notifyOwner: false,
    notifyDev: true,
    customerMessage: 'Tive uma instabilidade para recuperar a etapa anterior. Poderia me confirmar novamente o que deseja fazer?'
